<template>
	<view class="uni-container">
		<uni-forms ref="form" v-model="formData" :rules="rules" validateTrigger="bind" @submit="submit">
			<uni-forms-item name="username" label="ућеТѕитљЇ" required>
				<uni-easyinput v-model="formData.username" :clearable="false" placeholder="У»иУЙЊтЁЦућеТѕитљЇ" />
			</uni-forms-item>
			<uni-forms-item name="nickname" label="ућеТѕиТўхуД░" required>
				<uni-easyinput v-model="formData.nickname" :clearable="false" placeholder="У»иУЙЊтЁЦућеТѕиТўхуД░" />
			</uni-forms-item>
			<uni-forms-item name="password" label="тѕЮтДІт»єуаЂ" required>
				<uni-easyinput v-model="formData.password" :clearable="false" placeholder="У»иУЙЊтЁЦтѕЮтДІт»єуаЂ" />
			</uni-forms-item>
			<uni-forms-item name="role" label="УДњУЅ▓тѕЌУАе" class="flex-center-x">
				<uni-data-checkbox multiple :localdata="roles" v-model="formData.role" />
			</uni-forms-item>
			<uni-forms-item name="tags" label="ућеТѕиТаЄуГЙ" labelWidth="100" class="flex-center-x">
				<uni-data-checkbox ref="checkbox" :multiple="true" v-model="formData.tags" collection="uni-id-tag"
					field="tagid as value, name as text"></uni-data-checkbox>
				<span class="link-btn" @click="gotoTagAdd">Тќ░тбъ</span>
				<span class="link-btn" @click="gotoTagList" style="margin-left: 10px;">у«Ауљє</span>
			</uni-forms-item>
			<uni-forms-item name="authorizedApp" label="тЈ»уЎ╗тйЋт║ћуће" labelWidth="100" class="flex-center-x">
				<uni-data-checkbox :multiple="true" v-model="formData.authorizedApp" collection="opendb-app-list"
					field="appid as value, name as text"></uni-data-checkbox>
				<span class="link-btn" @click="gotoAppList">у«Ауљє</span>
			</uni-forms-item>
			<uni-forms-item name="mobile" label="ТЅІТю║тЈи">
				<uni-easyinput v-model="formData.mobile" :clearable="false" placeholder="У»иУЙЊтЁЦТЅІТю║тЈи" />
			</uni-forms-item>
			<uni-forms-item name="email" label="жѓ«у«▒">
				<uni-easyinput v-model="formData.email" :clearable="false" placeholder="У»иУЙЊтЁЦжѓ«у«▒" />
			</uni-forms-item>
			<uni-forms-item name="status" label="Тў»тљдтљ»уће">
				<switch @change="binddata('status', $event.detail.value)" :checked="formData.status" />
			</uni-forms-item>
			<view class="uni-button-group">
				<button style="width: 100px;" type="primary" class="uni-button"
					@click="submitForm">{{$t('common.button.submit')}}</button>
				<navigator open-type="navigateBack" style="margin-left: 15px;"><button style="width: 100px;"
						class="uni-button">{{$t('common.button.back')}}</button></navigator>
			</view>
		</uni-forms>
	</view>
</template>

<script>
	import {
		validator
	} from '@/js_sdk/validator/uni-id-users.js';

	const db = uniCloud.database();
	const dbCmd = db.command;
	const dbCollectionName = 'uni-id-users';

	function getValidator(fields) {
		let result = {}
		for (let key in validator) {
			if (fields.includes(key)) {
				result[key] = validator[key]
			}
		}
		return result
	}

	export default {
		data() {
			return {
				formData: {
					"username": "",
					"nickname": "",
					"password": "",
					"role": [],
					"authorizedApp": [],
					"tags": [],
					"mobile": undefined,
					"email": undefined,
					"status": true //ж╗ўУ«цтљ»уће
				},
				rules: {
					...getValidator(["username", "password", "role", "mobile", "email"]),
					"status": {
						"rules": [{
							"format": "bool"
						}]
					}
				},
				roles: []
			}
		},
		onLoad() {
			this.loadroles()
		},
		methods: {
			/**
			 * Уи│Уйгт║ћућеу«Ауљєуџё list жАх
			 */
			gotoAppList() {
				uni.navigateTo({
					url: '../app/list'
				})
			},
			gotoTagList() {
				uni.navigateTo({
					url: '../tag/list'
				})
			},
			gotoTagAdd() {
				uni.navigateTo({
					url: '../tag/add',
					events: {
						refreshCheckboxData: () => {
							this.$refs.checkbox.loadData()
						}
					}
				})
			},

			/**
			 * УДдтЈЉУАетЇЋТЈљС║ц
			 */
			submitForm() {
				this.$refs.form.submit();
			},

			/**
			 * УАетЇЋТЈљС║ц
			 * @param {Object} event тЏъУ░ЃтЈѓТЋ░ Function(callback:{value,errors})
			 */
			submit(event) {
				const {
					value,
					errors
				} = event.detail

				// УАетЇЋТаАжфїтц▒У┤ЦжАхжЮбС╝џТЈљуц║ТіЦжћЎ №╝їУдЂтЂюТГбУАетЇЋТЈљС║цжђ╗УЙЉ
				if (errors) {
					return
				}
				uni.showLoading({
					title: 'ТЈљС║цСИГ...',
					mask: true
				})
				// Тў»тљдтљ»ућетіЪУЃйуџёТЋ░ТЇ«у▒╗тъІУйгТЇб№╝ї 0 ТГБтИИ№╝ї 1 удЂуће
				if (typeof value.status === "boolean") {
					value.status = Number(!value.status)
				}
				this.$request('addUser', value).then(() => {
					uni.showToast({
						title: 'Тќ░тбъТѕљтіЪ'
					})
					this.getOpenerEventChannel().emit('refreshData')
					setTimeout(() => uni.navigateBack(), 500)
				}).catch(err => {
					uni.showModal({
						content: err.message || 'У»иТ▒ѓТюЇтіАтц▒У┤Ц',
						showCancel: false
					})
				}).finally(err => {
					uni.hideLoading()
				})
			},
			loadroles() {
				db.collection('uni-id-roles').limit(500).get().then(res => {
					const roleIds = []
					this.roles = res.result.data.map(item => {
						roleIds.push(item.role_id)
						return {
							value: item.role_id,
							text: item.role_name
						}
					})
					if (roleIds.indexOf('admin') === -1) {
						this.roles.unshift({
							value: 'admin',
							text: 'УХЁу║Ду«АуљєтЉў'
						})
					}
				}).catch(err => {
					uni.showModal({
						title: 'ТЈљуц║',
						content: err.message,
						showCancel: false
					})
				})
			}
		}
	}
</script>
<style>
	::v-deep .uni-forms-item__label {
		width: 90px !important;
	}
</style>
